use fastly::http::{header, Method, StatusCode};
use fastly::{mime, Error, Request, Response};

const BACKEND_API: &str = "api_backend";
const BACKEND_STATIC: &str = "static_backend";
const BACKEND_AUTH: &str = "auth_backend";

#[fastly::main]
fn main(mut req: Request) -> Result<Response, Error> {
    let path = req.get_path();
    let method = req.get_method();

    let backend_name = match (method, path) {
        (_, path) if path.starts_with("/api/") => BACKEND_API,
        (_, path) if path.starts_with("/auth/") || path.starts_with("/login") => BACKEND_AUTH,
        (Method::GET, path) if path.starts_with("/static/") || path.ends_with(".css") || path.ends_with(".js") || path.ends_with(".png") => {
            BACKEND_STATIC
        }
        _ => BACKEND_API,
    };

    match send_to_backend(&mut req, backend_name) {
        Ok(resp) => Ok(resp),
        Err(e) => {
            eprintln!("Backend error: {}", e);
            Ok(Response::from_status(StatusCode::BAD_GATEWAY)
                .with_body_text_plain(&format!("Backend error: {}", e)))
        }
    }
}

fn send_to_backend(req: &mut Request, backend_name: &str) -> Result<Response, Error> {
    req.set_header(header::HOST, get_backend_host(backend_name));
    
    add_forwarding_headers(req);

    let mut beresp = req.clone_without_body().send(backend_name)?;
    
    if let Some(body) = req.take_body() {
        beresp = req.clone_with_body(body).send(backend_name)?;
    }

    process_backend_response(beresp, backend_name)
}

fn get_backend_host(backend_name: &str) -> &str {
    match backend_name {
        BACKEND_API => "api.example.com",
        BACKEND_STATIC => "static.example.com",
        BACKEND_AUTH => "auth.example.com",
        _ => "default.example.com",
    }
}

fn add_forwarding_headers(req: &mut Request) {
    if let Some(client_ip) = req.get_client_ip_addr() {
        let ip_str = client_ip.to_string();
        
        if let Some(existing) = req.get_header_str("X-Forwarded-For") {
            req.set_header("X-Forwarded-For", format!("{}, {}", existing, ip_str));
        } else {
            req.set_header("X-Forwarded-For", ip_str);
        }
    }

    if req.get_header_str("X-Forwarded-Proto").is_none() {
        req.set_header("X-Forwarded-Proto", "https");
    }

    req.set_header("X-Forwarded-Host", req.get_header_str(header::HOST).unwrap_or(""));
}

fn process_backend_response(mut resp: Response, backend_name: &str) -> Result<Response, Error> {
    resp.set_header("X-Backend", backend_name);
    resp.set_header("X-Cache", "MISS");
    
    if resp.get_status().is_server_error() {
        eprintln!("Backend {} returned error: {}", backend_name, resp.get_status());
    }

    Ok(resp)
}